/* $Id: fpuex.c,v 1.2 2012/07/17 18:22:54 kostik Exp kostik $ */
#include <sys/types.h>
#include <err.h>
#include <errno.h>
#include <signal.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ucontext.h>
#if defined(__amd64__)
#include <machine/fpu.h>
#elif defined(__i386__)
#include <machine/npx.h>
#endif

static void
handler(int signo __unused, siginfo_t *info, void *v)
{
	ucontext_t *uap;
	mcontext_t *mc;
#if defined(__amd64__)
	struct savefpu *sf;
#elif defined(__i386__)
	struct savexmm *sf;
#endif

	uap = v;
	mc = &uap->uc_mcontext;
	sf = &mc->mc_fpstate;
	printf("intr handler: trapno %d code %d cw 0x%04x sw 0x%04x mxcsr 0x%08x ip 0x%lx\n",
	    info->si_trapno, info->si_code,
#if defined(__amd64__)
	    sf->sv_env.en_cw, sf->sv_env.en_sw, sf->sv_env.en_mxcsr,
	    sf->sv_env.en_rip
#elif defined(__i386__)
	    sf->sv_env.en_cw, sf->sv_env.en_sw,
	    sf->sv_env.en_mxcsr, (unsigned long)sf->sv_env.en_fip
#endif
	    );
	exit(0);
}

double a[3];

double x(void) __attribute__((noinline));
double
x(void)
{

	a[3] = a[0] / a[1];
	return (a[3]);
}

int
main(void)
{
	struct sigaction sa;
	uint32_t mxcsr;
	uint16_t cw;

	bzero(&sa, sizeof(sa));
	sa.sa_sigaction = handler;
	sa.sa_flags = SA_SIGINFO;
	if (sigaction(SIGFPE, &sa, NULL) == -1)
		err(1, "sigaction SIGFPE");

	mxcsr = 0;
	__asm __volatile("ldmxcsr %0" : : "m" (mxcsr));
#ifdef __i386__
	cw = 0;
	__asm __volatile("fldcw %0" : : "m" (cw));
#endif
	a[0] = 1.0;
	a[1] = 0.0;
	x();
	return (0);
}



